    private function installer(): void
    {
        $checks = ['PHP 8.3+' => PHP_VERSION_ID >= 80300, 'PDO' => extension_loaded('pdo'), 'cURL' => extension_loaded('curl'), 'ZIP' => extension_loaded('zip'), 'JSON' => extension_loaded('json'), 'mbstring' => extension_loaded('mbstring'), 'OpenSSL' => extension_loaded('openssl')];
        $drivers = extension_loaded('pdo') ? PDO::getAvailableDrivers() : []; $checks['SQLite or MySQL PDO driver'] = in_array('sqlite', $drivers, true) || in_array('mysql', $drivers, true);
        try { Config::ensureStorage(); $checks['Writable storage'] = is_writable(MODRIGHT_ROOT . '/storage'); } catch (\Throwable) { $checks['Writable storage'] = false; }
        $error = '';
        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
