            if (in_array(false, $checks, true)) $error = 'Resolve failed environment checks before installing.';
            else {
                try {
                    $driver = (string) ($_POST['driver'] ?? 'sqlite');
                    if (!in_array($driver, ['sqlite', 'mysql'], true) || !in_array($driver, $drivers, true)) throw new \InvalidArgumentException('Selected database driver is unavailable.');
                    $config = ['app_key' => bin2hex(random_bytes(32)), 'cron_token' => bin2hex(random_bytes(32)), 'database' => ['driver' => $driver, 'path' => trim((string) ($_POST['sqlite_path'] ?? 'storage/data/modright.sqlite')), 'host' => trim((string) ($_POST['db_host'] ?? 'localhost')), 'port' => (int) ($_POST['db_port'] ?? 3306), 'name' => trim((string) ($_POST['db_name'] ?? '')), 'user' => trim((string) ($_POST['db_user'] ?? '')), 'password' => (string) ($_POST['db_password'] ?? '')]];
                    if ($driver === 'sqlite') Database::sqlitePath($config['database']['path']);
                    $username = trim((string) ($_POST['username'] ?? 'admin')); $password = (string) ($_POST['password'] ?? '');$passwordConfirmation=(string)($_POST['password_confirmation']??'');$email=UserService::normalizeEmail((string)($_POST['email']??''));
                    if (!preg_match('/^[A-Za-z0-9_.-]{3,50}$/', $username) || strlen($password) < 12) throw new \InvalidArgumentException('Use a valid username and a password of at least 12 characters.');
                    if(!hash_equals($password,$passwordConfirmation))throw new \InvalidArgumentException('The administrator passwords do not match.');
                    if($email===null)throw new \InvalidArgumentException('Enter a valid administrator email address.');
                    Config::write($config); $db = Database::connect($config); Database::migrate($db);
                    $id=Database::id();$now=Database::now();$stmt=$db->prepare('INSERT INTO admins (id,username,password_hash,created_at) VALUES (?,?,?,?)'); $stmt->execute([$id,$username,password_hash($password,PASSWORD_DEFAULT),$now]);
                    Database::migrate($db);$db->prepare('UPDATE users SET email=?,email_verified_at=? WHERE id=?')->execute([$email,$now,$id]);
                    file_put_contents(MODRIGHT_ROOT . '/storage/installed.lock', Database::now(), LOCK_EX);
                    header('Location: ' . self::url('login')); exit;
                } catch (\Throwable $e) { @unlink(Config::FILE); $error = $e->getMessage(); }
            }
        }
        $checkHtml = '<ul class="checks">'; foreach ($checks as $label=>$ok) $checkHtml .= '<li class="' . ($ok?'ok':'bad') . '">' . ($ok?'✓':'✗') . ' ' . Security::escape($label) . '</li>'; $checkHtml .= '</ul>';
        $installerProxies=array_values(array_filter(array_map('trim',explode(',',(string)getenv('COGWORK_TRUSTED_PROXIES')))));$httpsNotice=RequestSecurity::https($_SERVER,$installerProxies)?'<p class="ok">HTTPS detected. Security-sensitive account features can be configured after installation.</p>':'<aside class="announcement warning"><div><strong>HTTPS was not detected</strong><p>Installation may continue for local evaluation, but password recovery, email verification, two-factor authentication, passkeys, and external authentication integrations remain disabled until a canonical HTTPS URL and any trusted reverse proxy are configured.</p></div></aside>';
        $body='<div class="card narrow"><h1>Install Cogwork Engine</h1><p>Build, maintain, and migrate modpacks.</p>'.$httpsNotice.$checkHtml.$this->error($error).'<form method="post" data-database-form>'.$this->csrf().'<label>Database<select name="driver" data-database-driver>';
        if(in_array('sqlite',$drivers,true))$body.='<option value="sqlite">SQLite (recommended)</option>'; if(in_array('mysql',$drivers,true))$body.='<option value="mysql">MySQL</option>';
        $body.='</select></label><details data-sqlite-settings><summary>Advanced SQLite settings</summary><label>Database path<input name="sqlite_path" value="storage/data/modright.sqlite" autocomplete="off"></label><p class="field-help">Relative paths start in the application directory. Absolute paths can place the database outside the public web directory.</p></details><details data-mysql-settings><summary>MySQL settings</summary><label>Host<input name="db_host" value="localhost"></label><label>Port<input name="db_port" type="number" value="3306"></label><label>Database<input name="db_name"></label><label>User<input name="db_user"></label><label>Password<input name="db_password" type="password"></label></details><label>Administrator username<input name="username" value="admin" required></label><label>Administrator email<input name="email" type="email" maxlength="254" required autocomplete="email"></label><label>Administrator password<input name="password" type="password" minlength="12" required autocomplete="new-password"></label><label>Repeat administrator password<input name="password_confirmation" type="password" minlength="12" required autocomplete="new-password"></label><button>Install</button></form></div>';
        $this->page('Install', $body, false);
    }

    private function login(): void
    {
        if (!empty($_SESSION['user_id'])||!empty($_SESSION['admin_id'])) { header('Location: '.self::url()); exit; }
        $error='';
        if($_SERVER['REQUEST_METHOD']==='POST'){
            Security::verifyCsrf();
            $locale=Translator::normalize((string)($_POST['locale']??$this->translator->locale()));$this->rememberLocale($locale);
            $subject=(string)($_POST['username']??'');$ip=(string)($_SERVER['REMOTE_ADDR']??'unknown');$config=Config::load();$throttle=new AuthThrottle($this->db,(string)$config['app_key']);$state=$throttle->check('login',$subject,$ip,5);
