            elseif(!$this->verifyCaptcha('login')){$throttle->record('login',$subject,$ip,false);$this->securityEvents()->record(null,'login.failed','warning',['reason'=>'captcha_rejected']);$error='Sign-in verification failed. Try again.';}
            else{$user=(new UserService($this->db))->authenticate($subject,(string)($_POST['password']??''));$throttle->record('login',$subject,$ip,$user!==null);
                if($user){$this->saveUserLocale((string)$user['id'],$locale);$settings=new SystemSettings($this->db);$twoFactorEnabled=$settings->feature('two_factor');$policy=(string)$settings->group('security')['two_factor_policy'];$hasTotp=$twoFactorEnabled&&$this->factorCount('user_totp',$user['id'],"confirmed_at<>''")>0;$hasPasskey=$twoFactorEnabled&&$settings->feature('passkeys')&&$this->factorCount('webauthn_credentials',$user['id'])>0;$required=$twoFactorEnabled&&($policy==='required_everyone'||($policy==='required_admins'&&$user['role']==='admin'));if($hasTotp||$hasPasskey){session_regenerate_id(true);$_SESSION['pending_user_id']=$user['id'];$_SESSION['pending_started_at']=time();header('Location: '.self::url('login/mfa'));exit;}$this->completeLogin($user,['password'],$required);return;}$this->securityEvents()->record(null,'login.failed','warning',['reason'=>'invalid_credentials']);Security::recordFailure();$error='Invalid credentials.';}
        }
        $this->page('Sign in','<div class="card narrow"><div class="auth-brand"><img src="assets/brand.svg" alt=""><div><strong>Cogwork Engine</strong><span>Build, maintain, and migrate modpacks.</span></div></div><h1>Sign in</h1>'.$this->error($error).'<form method="post"'.$this->captchaAttributes('login').'>'.$this->csrf().'<input type="hidden" name="recaptcha_token" data-recaptcha-token><label>Username<input name="username" required autofocus autocomplete="username"></label><label>Password<input name="password" type="password" required autocomplete="current-password"></label><label>Language<select name="locale">'.$this->localeOptions().'</select></label><button>Sign in</button></form><p><a href="'.self::url('password/forgot').'">Forgot password?</a></p></div>',false);
    }

    private function forgotPassword(): void
    {
        $message='';if($_SERVER['REQUEST_METHOD']==='POST'){Security::verifyCsrf();$settings=new SystemSettings($this->db);if(!$settings->feature('password_recovery'))throw new HttpException(503,'Password recovery is not enabled.');$config=Config::load();$email=(string)($_POST['email']??'');$ip=(string)($_SERVER['REMOTE_ADDR']??'unknown');$throttle=new AuthThrottle($this->db,(string)$config['app_key']);if($this->verifyCaptcha('forgot')){$service=new PasswordRecoveryService($this->db,new UserService($this->db),$throttle,$this->mail(),new SessionService($this->db,(string)$config['app_key']),$settings);try{$service->request($email,$ip);}catch(\Throwable $e){error_log('[Cogwork recovery] '.$e->getMessage());}}else{$throttle->record('password_request',$email,$ip,false);$this->securityEvents()->record(null,'password_recovery.rejected','warning',['reason'=>'captcha_rejected']);}$message='If that address belongs to an account, a reset link has been sent.';}
        $this->page('Forgot password','<div class="card narrow"><a href="'.self::url('login').'">← Sign in</a><h1>Forgot password</h1><p>Enter your account email. The response is the same whether or not an account exists.</p>'.($message?'<p class="ok">'.Security::escape($message).'</p>':'').'<form method="post"'.$this->captchaAttributes('forgot').'>'.$this->csrf().'<input type="hidden" name="recaptcha_token" data-recaptcha-token><label>Email<input type="email" name="email" required autocomplete="email"></label><button>Send reset link</button></form></div>',false);
    }

