        elseif($key==='package_id'&&$this->authorization?->can($packId,'build')){$stmt=$this->db->prepare('SELECT COUNT(*) FROM packages WHERE id=? AND pack_id=?');$stmt->execute([$text,$packId]);if((int)$stmt->fetchColumn()===1)$url=self::url('packages/download',['id'=>$text]);}
        elseif($key==='manifest_id'&&$this->authorization?->can($packId,'build')){$stmt=$this->db->prepare('SELECT COUNT(*) FROM build_manifests WHERE id=? AND pack_id=?');$stmt->execute([$text,$packId]);if((int)$stmt->fetchColumn()===1)$url=self::url('packs/view',['id'=>$packId]).'#build-manifests';}
        elseif($key==='migration_manifest_id'&&$this->authorization?->can($packId,'migrate')){$stmt=$this->db->prepare('SELECT scan_id FROM migration_manifests WHERE id=? AND (source_pack_id=? OR target_pack_id=?)');$stmt->execute([$text,$packId,$packId]);if($scanId=$stmt->fetchColumn())$url=self::url('packs/migrate/results',['id'=>$scanId]);}
        elseif($key==='validation_id'){$stmt=$this->db->prepare('SELECT COUNT(*) FROM validation_reports WHERE id=? AND pack_id=?');$stmt->execute([$text,$packId]);if((int)$stmt->fetchColumn()===1)$url=self::url('packs/validation-report',['id'=>$text]);}
        elseif($key==='backup_id'&&$this->authorization?->can($packId,'edit_metadata')){$stmt=$this->db->prepare('SELECT COUNT(*) FROM backups WHERE id=? AND pack_id=?');$stmt->execute([$text,$packId]);if((int)$stmt->fetchColumn()===1)$url=self::url('packs/view',['id'=>$packId]).'#backups';}
