    private function migrationPlanner(): void
    {
        $pack=$this->packs->find((string)($_GET['id']??$_POST['id']??''));$catalog=new VersionCatalog();$versions=$catalog->minecraft();$current=array_search($pack['game_version'],$versions,true);$candidates=$current===false?array_slice($versions,0,8):array_slice($versions,0,$current);$candidates=array_slice(array_reverse($candidates),0,8);$error='';
        if($_SERVER['REQUEST_METHOD']==='POST'){Security::verifyCsrf();try{$games=array_values(array_unique(array_filter(array_map('strval',$_POST['games']??[]))));$loaders=array_values(array_intersect(['fabric','forge','neoforge','quilt'],array_map('strval',$_POST['loaders']??[])));if($games===[]||$loaders===[])throw new \InvalidArgumentException('Select at least one Minecraft version and loader.');$targets=[];foreach($games as$game)foreach($loaders as$loader){try{$loaderVersions=$catalog->loaders($loader,$game);if($loaderVersions!==[])$targets[]=['game'=>$game,'loader'=>$loader,'loader_version'=>$loaderVersions[0]];}catch(\Throwable){}}if($targets===[])throw new \RuntimeException('No loader versions are available for the selected combinations.');$migrations=new MigrationService($this->db,$this->packs);$scanId=$migrations->createScan($pack['id'],$targets,isset($_POST['allow_beta']));$job=$this->jobs->create('migration_scan',$pack['id'],['scan_id'=>$scanId]);header('Location: '.self::url('jobs/view',['id'=>$job]));exit;}catch(\Throwable$e){$error=$e->getMessage();}}
        $gameFields='';foreach($candidates as$i=>$version)$gameFields.='<label class="check"><input type="checkbox" name="games[]" value="'.Security::escape($version).'"'.($i===0?' checked':'').'> Minecraft '.Security::escape($version).'</label>';$loaderFields='';foreach(['forge'=>'Forge','neoforge'=>'NeoForge','fabric'=>'Fabric','quilt'=>'Quilt']as$key=>$label)$loaderFields.='<label class="check"><input type="checkbox" name="loaders[]" value="'.$key.'"'.($key===$pack['loader']?' checked':'').'> '.$label.'</label>';
        $notice=$catalog->notice()?'<p class="warning">'.Security::escape($catalog->notice()).'</p>':'';$body='<div class="heading"><div><a href="'.self::url('packs/view',['id'=>$pack['id']]).'">← '.Security::escape($pack['name']).'</a><h1>Migration planner</h1><p>Compare newer Minecraft releases and loaders without changing the source pack.</p></div><a class="button secondary" href="'.self::url('migration/replacements').'">Replacement mappings</a></div><div class="card narrow">'.$this->error($error).$notice.'<p><strong>Current target:</strong> Minecraft '.Security::escape($pack['game_version'].' · '.$pack['loader'].' '.$pack['loader_version']).'</p><form method="post">'.$this->csrf().'<input type="hidden" name="id" value="'.$pack['id'].'"><fieldset><legend>Newer Minecraft releases</legend>'.$gameFields.'</fieldset><fieldset><legend>Loaders to explore</legend>'.$loaderFields.'</fieldset><label class="check"><input type="checkbox" name="allow_beta"> Include beta and alpha mod releases</label><p class="field-help">The newest stable loader version for each combination is selected automatically. The scan is resumable and treats API failures as unknown.</p><button>Start compatibility scan</button></form></div>';
        $this->page('Migration planner',$body);
