        $this->requireRecentAuthentication();
        $config=Config::load();$totp=new TotpService($this->db,(string)$config['app_key']);$error='';$pending=$_SESSION['totp_enrollment']??null;if(!is_array($pending)||!is_string($pending['sealed']??null)){$created=$totp->begin((string)$this->currentUser['id'],(string)$this->currentUser['username']);$pending=['sealed'=>$created['sealed'],'created_at'=>time()];$_SESSION['totp_enrollment']=$pending;}if((int)($pending['created_at']??0)<time()-900){unset($_SESSION['totp_enrollment']);throw new HttpException(403,'Authenticator enrollment expired. Start again.');}$enrollment=$totp->resume((string)$pending['sealed'],(string)$this->currentUser['username']);
