        $qr=(new \chillerlan\QRCode\QRCode())->render((string)$enrollment['uri']);$this->page('Set up authenticator','<div class="card narrow"><a href="'.self::url('account').'">← Account</a><h1>Set up authenticator app</h1>'.$this->error($error).'<p>Scan this QR code, or enter the setup key manually. Then enter the current six-digit code.</p><img class="totp-qr" src="'.Security::escape($qr).'" alt="QR code containing the authenticator setup URI"><label>Manual setup key<input readonly value="'.Security::escape((string)$enrollment['secret']).'"></label><form method="post">'.$this->csrf().'<label>Authentication code<input name="code" inputmode="numeric" pattern="[0-9]{6}" autocomplete="one-time-code" required></label><button>Confirm and generate recovery codes</button></form></div>');
