        elseif($tab==='system'){$health=(new HealthService($this->db,new SystemSettings($this->db)))->report($_SERVER);$checks='';foreach($health['checks']as$check)$checks.='<tr><td>'.Security::escape((string)$check['id']).'</td><td><span class="status-label '.Security::escape((string)$check['status']).'">'.Security::escape(ucfirst((string)$check['status'])).'</span></td><td>'.Security::escape((string)$check['message']).'</td><td>'.Security::escape((string)$check['recommendation']).'</td></tr>';$restore=(string)($_SESSION['restore_message']??'');unset($_SESSION['restore_message']);$view=$this->systemView();$content=($restore?'<aside class="announcement success" role="status"><div><strong>Restore completed</strong><p>'.Security::escape($restore).'</p></div></aside>':'').$this->systemNavigation($view).'<section class="card system-health"'.($view!=='overview'?' hidden':'').'><div class="system-panel-heading"><div><h2>System health</h2><p>Cogwork Engine '.Security::escape((string)$health['version']).' · Overall status: <strong>'.Security::escape(ucfirst((string)$health['status'])).'</strong></p></div><a class="button secondary" href="'.self::url('admin/diagnostics').'">Download redacted diagnostics</a></div><div class="table-wrap"><table><thead><tr><th>Check</th><th>Status</th><th>Details</th><th>Recommendation</th></tr></thead><tbody>'.$checks.'</tbody></table></div></section><div class="system-settings" data-system-view="'.Security::escape($view).'">'.$this->systemControlPanel().$this->systemOperationsPanel().'<!-- system-panels-end --></div>';}
