    private function systemView():string
    { $view=(string)($_GET['view']??'overview');return in_array($view,['overview','features','security','integrations','maintenance','data','updates'],true)?$view:'overview'; }

    private function systemNavigation(string$view):string
    {
        $items=['overview'=>['Overview','Health and diagnostics'],'features'=>['Features','Application capabilities'],'security'=>['Security','HTTPS, sessions and recovery'],'integrations'=>['Integrations','Mail, Modrinth and proxies'],'maintenance'=>['Maintenance','Availability and announcements'],'data'=>['Data & backups','Retention, backup and restore'],'updates'=>['Updates','Releases and upgrade readiness']];$links='';
        foreach($items as$key=>[$title,$description])$links.='<a class="system-nav-card'.($view===$key?' active':'').'" href="'.self::url('admin',['tab'=>'system','view'=>$key]).'"'.($view===$key?' aria-current="page"':'').'><strong>'.$title.'</strong><span>'.$description.'</span></a>';
        return'<nav class="system-nav" aria-label="System settings sections">'.$links.'</nav>';
    }

    private function categorizeSystemPanels(string$content):string
    {
        $groups=['Features'=>'features','Feature reference and diagnostics'=>'features','Security and public URL'=>'security','Password recovery policy'=>'security','Emergency recovery'=>'security','Google reCAPTCHA'=>'security','Mail delivery'=>'integrations','Modrinth connectivity and proxy'=>'integrations','Modrinth proxy bypass'=>'integrations','General outbound proxy'=>'integrations','Maintenance mode'=>'maintenance','Maintenance processing policy'=>'maintenance','Retention and configuration'=>'data','Retention policy'=>'data','Backups, restore, migration mappings, and cron'=>'data','Update-check settings'=>'updates','Release details and manual upgrade'=>'updates'];
        foreach($groups as$title=>$group)$content=str_replace('<details><summary>'.$title.'</summary>','<details data-system-group="'.$group.'"><summary>'.$title.'</summary>',$content);
        $content=str_replace('<div class="system-summary"><h2>Updates</h2>','<div class="system-summary" data-system-group="updates"><h2>Updates</h2>',$content);
        $content=str_replace('<p><a class="button secondary" href="'.self::url('admin/announcements').'">Manage announcements</a></p>','<p data-system-group="maintenance"><a class="button secondary" href="'.self::url('admin/announcements').'">Manage announcements</a></p>',$content);
        $content=str_replace('<p><a class="button secondary" href="'.self::url('admin/maintenance/preview').'">Preview maintenance page</a></p>','<p data-system-group="maintenance"><a class="button secondary" href="'.self::url('admin/maintenance/preview').'">Preview maintenance page</a></p>',$content);
        $content=str_replace('<form method="post" action="'.self::url('admin/connectivity/test').'">','<form data-system-group="integrations" method="post" action="'.self::url('admin/connectivity/test').'">',$content);
        return$content;
    }

    private function modrinthProxyBypassPanel(): string
