        $configured=is_array($configured)?array_map('strval',$configured):[];
        $fields='';
        foreach(ModrinthClient::ALLOWED_HOSTS as$host)$fields.='<label class="check"><input type="checkbox" name="bypass[]" value="'.Security::escape($host).'"'.(in_array($host,$configured,true)?' checked':'').'> <code>'.Security::escape($host).'</code></label>';
        return'<details><summary>Modrinth proxy bypass</summary><p>Selected approved destinations connect directly when the Modrinth proxy is enabled. Custom destinations are intentionally not accepted.</p><form method="post" action="'.self::url('admin/system/save').'">'.$this->csrf().'<input type="hidden" name="section" value="connectivity_bypass"><div class="form-grid">'.$fields.'</div><button>Save proxy bypass</button></form></details>';
