ces.</p></div></div><section class="card"><form method="post">'.$this->csrf().'<div class="form-grid"><label>Severity<select name="severity"><option>info</option><option>success</option><option>warning</option><option>maintenance</option><option>critical</option></select></label><label>Audience<select name="audience"><option value="everyone">Everyone</option><option value="authenticated">Authenticated users</option><option value="administrators">Administrators</option><option value="pack_owners">Pack owners</option></select></label><label>English title<input name="title_en" required></label><label>German title<input name="title_de"></label></div><label>English message<textarea name="message_en" required></textarea></label><label>German message<textarea name="message_de"></textarea></label><label>Internal or HTTPS link<input name="target_url"></label><div class="form-grid"><label>Starts at (UTC)<input type="datetime-local" name="starts_at"></label><label>Ends at (UTC)<input type="datetime-local" name="ends_at"></label></div><label class="check"><input type="checkbox" name="dismissible" checked> Dismissible (critical and maintenance notices always remain visible)</label><button>Create announcement</button></form></section><section class="card"><div class="table-wrap"><table><thead><tr><th>Title</th><th>Severity</th><th>Audience</th><th>Schedule</th><th></th></tr></thead><tbody>'.($rows?:'<tr><td colspan="5">No announcements.</td></tr>').'</tbody></table></div></section>'); }
