s->csrf().'<input type="hidden" name="id" value="'.$pack['id'].'"><label>User<select name="user_id">'.$options.'</select></label><label>Permission preset<select name="preset"><option value="viewer">Viewer</option><option value="contributor">Contributor</option><option value="maintainer">Maintainer</option><option value="custom">Custom</option></select></label><details><summary>Custom permissions</summary>'.$checks.'</details><button>Share pack</button> <button class="secondary" name="transfer" value="1" data-confirm="Transfer ownership to this user?">Transfer ownership</button></form></div><div class="card"><h2>Shared access</h2><table><thead><tr><th>User</th><th>Preset</th><th>Permissions</th><th></th></tr></thead><tbody>'.($rows?:'<tr><td colspan="4">This pack is private.</td></tr>').'</tbody></table></div>';$this->page('Share pack',$body); }

    private function tutorial(): void
    { $user=$this->currentUser;$step=max(0,(int)($_GET['step']??$user['tutorial_step']??0));$steps=[['Welcome to Cogwork Engine','The dashboard contains every pack you own or that another user shared with you.'],['Create or import','Create an empty pack or import an existing .mrpack, then review its contents before saving.'],['Synchronize and validate','Refresh metadata, synchronize files, and run validation before updates or builds.'],['Build and migrate','Create client or server packages, or compare newer Minecraft and loader targets in the migration planner.'],['Sharing and safety','Owners can share precise permissions. Keep backups and test migrated worlds before production.']];if($this->authorization->admin())$steps[]=['Administration','Administrators manage accounts, backups, replacement mappings, and every pack from the header and settings pages.'];$step=min($step,count($steps)-1);[$heading,$description]=$steps[$step];$body='<div class="card narrow tutorial"><span>Step '.($step+1).' of '.count($steps).'</span><h1>'.Security::escape($heading).'</h1><p>'.Security::escape($description).'</p><form method="post" action="'.self::url('tutorial/update').'">'.$this->csrf().'<input type="hidden" name="step" value="'.$step.'"><button class="secondary" name="action" value="skip">Skip tutorial</button> '.($step>0?'<button class="secondary" name="action" value="previous">Previous</button> ':'').'<button name="action" value="'.($step===count($steps)-1?'complete':'next').'">'.($step===count($steps)-1?'Finish':'Next').'</button></form></div>';$this->page('Tutorial',$body); }

    private function updateTutorial(): void
    { if($_SERVER['REQUEST_METHOD']!=='POST')throw new HttpException(405,'POST required.');Security::verifyCsrf();$step=max(0,(int)($_POST['step']??0));$action=(string)($_POST['action']??'next');$service=new UserService($this->db);if($action==='skip'){$service->tutorial($this->currentUser['id'],'skipped',$step);$next=0;}elseif($action==='complete'){$service->tutorial($this->currentUser['id'],'completed',$step);$next=$step;}elseif($action==='restart'){$next=0;$service->tutorial($this->currentUser['id'],'in_progress',0);}else{$next=$action==='previous'?max(0,$step-1):$step+1;$service->tutorial($this->currentUser['id'],'in_progress',$next);}if(isset($_POST['json'])){header('Content-Type: application/json');echo json_encode(['ok'=>true,'step'=>$next,'status'=>$action],JSON_THROW_ON_ERROR);exit;}header('Location: '.self::url(in_array($action,['skip','complete'],true)?'':'tutorial',['step'=>$next]));exit; }

    /** @return list<array{route:string,selector:string,title:string,text:string,interactive:bool}> */
    private function tourSteps():array
    { $steps=[['route'=>'','selector'=>'[data-account-menu] summary','title'=>'Your account menu','text'=>'Open this menu to reach your account, password, language, administration, and sign-out controls.','interactive'=>true],['route'=>'','selector'=>'a[href*="route=packs%2Fcreate"]','title'=>'Create a modpack','text'=>'Click New pack to open the real creation form.','interactive'=>true],['route'=>'packs/create','selector'=>'[data-minecraft-version]','title'=>'Compatible versions','text'=>'Try the Minecraft selector. Loader releases update to match the selected Minecraft version.','interactive'=>false],['route'=>'','selector'=>'a[href*="route=packs%2Fimport"]','title'=>'Import an existing pack','text'=>'Click Import archive to review an .mrpack before anything is saved permanently.','interactive'=>true],['route'=>'packs/import','selector'=>'input[type="file"]','title'=>'Choose an .mrpack','text'=>'This is the local archive picker. You can interact with it now, or continue without selecting a file.','interactive'=>false],['route'=>'account','selector'=>'#security','title'=>'Account security','text'=>'Review sessions, TOTP, recovery codes, and passkeys here. Factor changes require recent authentication.','interactive'=>false],['route'=>'notifications','selector'=>'h1','title'=>'Notification center','text'=>'Security and workflow notices remain here even if email delivery fails. Preferences are available below the list.','interactive'=>false]];if($this->authorization?->admin())$steps[]=['route'=>'admin','selector'=>'.admin-tabs','title'=>'Administration','text'=>'Use Packs, Users, System, and Audit to manage the installation. Open System for health, features, mail, proxies, maintenance, retention, and updates.','interactive'=>true];else$steps[]=['route'=>'help','selector'=>'h1','title'=>'Help center','text'=>'Search the offline help center whenever you need a workflow explanation.','interactive'=>false];return$steps; }

    /** @return array<string,mixed> */
    private function tourConfig(int$step):array
    { $steps=$this->tourSteps();$step=max(0,min(count($steps)-1,$step));$item=$steps[$step];$item['title']=$this->translator->text($item['title']);$item['text']=$this->translator->text($item['text']);$next=min(count($steps)-1,$step+1);$previous=max(0,$step-1);return$item+['step'=>$step,'total'=>count($steps),'last'=>$step===count($steps)-1,'update_url'=>self::url('tutorial/update'),'return_url'=>self::url(),'next_url'=>self::url($steps[$next]['route'],['tour'=>1,'step'=>$next]),'previous_url'=>self::url($steps[$previous]['route'],['tour'=>1,'step'=>$previous]),'csrf'=>Security::csrfToken(),'labels'=>['step'=>$this->translator->text('Step {current} of {total}'),'previous'=>$this->translator->text('Previous'),'next'=>$this->translator->text('Next'),'finish'=>$this->translator->text('Finish'),'skip'=>$this->translator->text('Skip tutorial'),'missing'=>$this->translator->text('This control is not available on this screen. You can continue to the next step.')]]; }

    private function helpCenter(): void
    {
        $query=mb_strtolower(trim((string)($_GET['q']??'')));
        $topics=[
            ['getting-started','Getting started','Create or import a pack, refresh its catalog, synchronize files, validate it, and then build a package.'],
            ['mods','Managing mods','Search Modrinth, add exact versions, upload private JARs, and use environment flags to control client and server inclusion.'],
            ['jobs','Background jobs','Keep the job page open or configure cron. Jobs are resumable, cancellable, and safe to retry.'],
            ['server','Server packs','Configure Java, memory, server.properties, EULA state, scripts, overrides, and exclusions before building a server ZIP. Test the ZIP with a copied world before production.'],
            ['migration','Migration planner','Compare Minecraft and loader targets, review blockers, unknown results, dependencies, and replacements, then create a separate migration copy. The planner provides evidence, not a guarantee that a world is safe.'],
            ['sharing','Sharing and permissions','Owners share Viewer, Contributor, Maintainer, or custom capabilities. Administrators can access every pack. Transfer ownership before deleting an owner.'],
            ['account-security','Account security','Use a unique password, review active sessions, and enable an authenticator or passkey. Save recovery codes offline. Password, email, factor, and session changes may require signing in again.'],
            ['account-recovery','Account recovery','Start with a saved recovery code when TOTP, Windows Hello, a security key, or a phone passkey is unavailable. If verified email and mail delivery work, use Forgot password for password loss; it does not bypass required 2FA. Another administrator can send a reset link or explicitly reset all factors, which revokes every session and creates a prominent audit event. If email is inaccessible, repair mail or verify the address through normal account controls before relying on recovery. If the final administrator loses every factor, use protected host/database recovery or restore a tested server backup—never email passwords, factor secrets, or reusable credentials.'],
            ['notifications','Notifications','The notification center keeps job, permission, maintenance, update, and security notices in the application even when email fails. Choose optional categories in Account; mandatory security notices cannot be disabled.'],
            ['administration','Administration','Administrators use Packs for ownership and access, Users for account and recovery management, System for health and configuration, and Audit for security and operational history.'],
            ['system','System settings','System contains health checks, feature controls, HTTPS and trusted-proxy settings, SMTP, reCAPTCHA, Modrinth and GitHub proxies, maintenance, announcements, retention, configuration transfer, and update readiness. Test changes before relying on them.'],
            ['maintenance','Maintenance and announcements','Maintenance blocks ordinary users with a temporary page while administrators retain access. Announcements can be scheduled and targeted. Preview maintenance and keep an emergency host-level recovery path.'],
            ['updates','Updates and upgrades','Cogwork Engine checks only the public GitHub release feed and never installs code automatically. Review requirements, create database and storage backups, verify the ZIP checksum, and keep matching files and data for rollback.'],
            ['privacy','Privacy and external services','Modrinth, GitHub update checks, SMTP, and optional Google reCAPTCHA contact external services. Administrators can disable optional connections. Diagnostics and configuration exports redact credentials and personal data.'],
            ['backup','Backups and recovery','Download regular application backups and keep independent database, storage, and Minecraft-world backups. The portable logical export excludes accounts and secrets and is not a complete disaster-recovery backup. Test restores periodically.'],
            ['glossary','Glossary','Loader: the mod runtime. Override: a file copied into the instance. Profile: a build variant. Environment: client/server support. Dependency: another required project. Canonical URL: the trusted public HTTPS address.'],
        ];
        $cards='';
        foreach($topics as[$slug,$topicTitle,$text]){
            $translatedTitle=$this->translator->text($topicTitle);$translatedText=$this->translator->text($text);
            if($query!==''&&!str_contains(mb_strtolower($translatedTitle.' '.$translatedText),$query))continue;
            $cards.='<article class="card" id="'.$slug.'"><h2>'.Security::escape($translatedTitle).'</h2><p>'.Security::escape($translatedText).'</p></article>';
        }
        $version=is_file(MODRIGHT_ROOT.'/VERSION')?trim((string)file_get_contents(MODRIGHT_ROOT.'/VERSION')):'unknown';
        $body='<div class="heading"><div><a href="'.self::url().'">← Modpacks</a><h1>Help center</h1><p>Practical guidance for every Cogwork Engine workflow.</p></div><form method="get"><input type="hidden" name="route" value="help"><input type="search" name="q" value="'.Security::escape($query).'" placeholder="Search help…"><button>Search</button></form></div><div class="grid">'.($cards?:'<div class="card empty">No help topics matched your search.</div>').'</div><div class="card"><form method="post" action="'.self::url('tutorial/update').'">'.$this->csrf().'<input type="hidden" name="step" value="0"><button name="action" value="next">Restart tutorial</button></form><p>Documentation for Cogwork Engine '.Security::escape($version).'</p></div>';
        $this->page('Help center',$body);
    }

    private function cron(): void
    {
        $config=Config::load();$settings=new SystemSettings($this->db);$state=(new MaintenanceService($settings))->state();
        if($state['active']&&!empty($state['pause_cron'])){http_response_code(503);header('Content-Type: application/json');if($state['retry_after'])header('Retry-After: '.(int)$state['retry_after']);echo json_encode(['processed'=>0,'status'=>'paused_for_maintenance'],JSON_THROW_ON_ERROR);return;}
        $token=(string)($_SERVER['HTTP_AUTHORIZATION']??$_GET['token']??'');$token=preg_replace('/^Bearer\s+/i','',$token);if(!hash_equals($config['cron_token'],$token))throw new HttpException(403,'Invalid cron token.');
        $started=Database::now();$count=0;
        try{
            if($settings->feature('announcements'))(new AnnouncementService($this->db))->reconcileLifecycle();
            try{(new UpdateService($this->db,$settings))->check(false,true);}catch(\Throwable){/* Update availability must never prevent queued work. */}
            $deadline=microtime(true)+20;while(microtime(true)<$deadline&&$count<10){if($this->jobs->nextQueued()===null)break;$count++;}
            $this->db->prepare('INSERT INTO cron_runs (id,status,processed,error,started_at,finished_at) VALUES (?,?,?,?,?,?)')->execute([Database::id(),'success',$count,'',$started,Database::now()]);header('Content-Type: application/json');echo json_encode(['processed'=>$count],JSON_THROW_ON_ERROR);
        }catch(\Throwable$e){$this->db->prepare('INSERT INTO cron_runs (id,status,processed,error,started_at,finished_at) VALUES (?,?,?,?,?,?)')->execute([Database::id(),'failed',$count,mb_substr($e->getMessage(),0,500),$started,Database::now()]);throw$e;}
    }

    private function loadCurrentUser(): void
    { $id=(string)($_SESSION['user_id']??$_SESSION['admin_id']??'');if($id==='')return;try{$user=(new UserService($this->db))->find($id);if((int)$user['enabled']!==1||isset($_SESSION['session_version'])&&(int)$_SESSION['session_version']!==(int)$user['session_version']){$_SESSION=[];return;}if(!empty($_SESSION['auth_token'])){$session=(new SessionService($this->db,(string)Config::load()['app_key']))->verify((string)$_SESSION['auth_token']);if(!$session||!hash_equals((string)$user['id'],(string)$session['user_id'])){$_SESSION=[];return;}(new SessionService($this->db,(string)Config::load()['app_key']))->touch((string)$session['id']);}$_SESSION['user_id']=$user['id'];$_SESSION['admin_id']=$user['role']==='admin'?$user['id']:null;$_SESSION['session_version']=(int)$user['session_version'];$this->currentUser=$user;$this->authorization=new Authorization($this->db,$user);}catch(\Throwable){$_SESSION=[];} }

    private function authorizeRoute(string $route): void
    {
        if($this->authorization===null)throw new HttpException(403,'Access denied.');
        if((str_starts_with($route,'admin/')||in_array($route,['admin','users','users/edit','users/profile','migration/replacements','settings','settings/backup','settings/restore'],true))&&!$this->authorization->admin())throw new HttpException(403,'Access denied.');
